const items = $input.all();
const results = [];

for (const item of items) {
  const f = item.json;

  const first = (v) => Array.isArray(v) ? (v[0] || null) : (v || null);
  const firstStr = (v) => { const r = first(v); return r != null ? String(r).trim() : null; };
  const toInt = (v) => { const n = parseInt(first(v)); return isNaN(n) ? null : n; };
  const toBool = (v) => {
    const val = firstStr(v);
    if (!val) return false;
    return val.toLowerCase() === 'oui' || val === 'true';
  };
  const toDate = (v) => {
    const val = firstStr(v);
    if (!val) return null;
    if (val.includes('/')) {
      const p = val.split('/');
      if (p.length === 3) return p[2] + '-' + p[1].padStart(2,'0') + '-' + p[0].padStart(2,'0');
    }
    if (val.includes('T')) return val.substring(0, 10);
    return val.substring(0, 10);
  };
  const arrJoin = (v) => {
    if (Array.isArray(v)) return v.join(', ');
    return v ? String(v) : null;
  };
  const esc = (v) => {
    if (v === null || v === undefined) return 'NULL';
    return "'" + String(v).replace(/'/g, "''").substring(0, 5000) + "'";
  };
  const num = (v) => (v !== null && v !== undefined) ? v : 'NULL';

  const j = {
    airtable_id: item.json.id,
    prenom: firstStr(f['Prénom jeune']),
    nom: firstStr(f['Nom de famille jeune']),
    email: firstStr(f['Email jeune']),
    telephone: firstStr(f['Numéro de téléphone Jeune']),
    age_inscription: toInt(f['Âge à l\'inscription']),
    ville: firstStr(f['Où tu habites ? (ville)'] || f['Où tu habites (ville)']),
    structure: firstStr(f['Nom de la structure (à partir de Structures)'] || f['Structures']),
    departement: firstStr(f['Département (from Structures)']),
    ville_structure: firstStr(f['Ville (à partir de Structures)']),
    referent: firstStr(f['Référent']),
    email_referent: firstStr(f['Email référent']),
    tel_referent: firstStr(f['Numéro du référent']),
    statut: firstStr(f['Statut de la demande']),
    binome_id: firstStr(f['Binôme ID']),
    prenom_benevole: firstStr(f['Prénom bénévole officiel']),
    nom_benevole: firstStr(f['Nom bénévole']),
    date_matching: toDate(f['Date de matching']),
    date_fin_mentorat: toDate(f['Date de fin de mentorat']),
    duree_mentorat: firstStr(f['Durée mentorat']),
    besoins: arrJoin(f['J\'ai besoin d\'aide pour']),
    mna: toBool(f['MNA']),
    es_tu: firstStr(f['Es-tu ...']),
    resume_suivi: firstStr(f['Résumé de suivi']),
    jours_depuis_suivi: toInt(f['Jours depuis dernier remplissage']),
    score_binome: firstStr(f['Score Binôme']),
    classification: firstStr(f['Classification Binôme']),
    dernier_mood: firstStr(f['Mood (à partir de Besoin d\'aide bénévoles MAJ)']),
    dernier_cr: firstStr(f['Compte rendu (à partir de Besoin d\'aide bénévoles MAJ)']),
    mentor_id: firstStr(f['Mentor']),
    structure_id: firstStr(f['Structures']),
    classe: firstStr(f['En quelle classe es-tu ?']),
    attentes_mentor: firstStr(f['Qu\'attends-tu de ton mentor et qu\'aimerais-tu accomplir avec lui/elle au cours de cet accompagnement ?']),
    niveau_francais_declare: firstStr(f['Ton niveau de français :']),
    secteur_vise: firstStr(f['Quel est ton secteur d\'activité ?'])
  };

  const sql = `INSERT INTO jeunes (airtable_id, prenom, nom, email, telephone, age_inscription, ville, structure, departement, ville_structure, referent, email_referent, tel_referent, statut, binome_id, prenom_benevole, nom_benevole, date_matching, date_fin_mentorat, duree_mentorat, besoins, mna, es_tu, resume_suivi, jours_depuis_suivi, score_binome, classification, dernier_mood, dernier_cr, mentor_id, structure_id, classe, attentes_mentor, niveau_francais_declare, secteur_vise, synced_at) VALUES (${esc(j.airtable_id)}, ${esc(j.prenom)}, ${esc(j.nom)}, ${esc(j.email)}, ${esc(j.telephone)}, ${num(j.age_inscription)}, ${esc(j.ville)}, ${esc(j.structure)}, ${esc(j.departement)}, ${esc(j.ville_structure)}, ${esc(j.referent)}, ${esc(j.email_referent)}, ${esc(j.tel_referent)}, ${esc(j.statut)}, ${esc(j.binome_id)}, ${esc(j.prenom_benevole)}, ${esc(j.nom_benevole)}, ${esc(j.date_matching)}, ${esc(j.date_fin_mentorat)}, ${esc(j.duree_mentorat)}, ${esc(j.besoins)}, ${j.mna}, ${esc(j.es_tu)}, ${esc(j.resume_suivi)}, ${num(j.jours_depuis_suivi)}, ${esc(j.score_binome)}, ${esc(j.classification)}, ${esc(j.dernier_mood)}, ${esc(j.dernier_cr)}, ${esc(j.mentor_id)}, ${esc(j.structure_id)}, ${esc(j.classe)}, ${esc(j.attentes_mentor)}, ${esc(j.niveau_francais_declare)}, ${esc(j.secteur_vise)}, NOW()) ON CONFLICT (airtable_id) DO UPDATE SET prenom=EXCLUDED.prenom, nom=EXCLUDED.nom, email=EXCLUDED.email, telephone=EXCLUDED.telephone, age_inscription=EXCLUDED.age_inscription, ville=EXCLUDED.ville, structure=EXCLUDED.structure, departement=EXCLUDED.departement, ville_structure=EXCLUDED.ville_structure, referent=EXCLUDED.referent, email_referent=EXCLUDED.email_referent, tel_referent=EXCLUDED.tel_referent, statut=EXCLUDED.statut, binome_id=EXCLUDED.binome_id, prenom_benevole=EXCLUDED.prenom_benevole, nom_benevole=EXCLUDED.nom_benevole, date_matching=EXCLUDED.date_matching, date_fin_mentorat=EXCLUDED.date_fin_mentorat, duree_mentorat=EXCLUDED.duree_mentorat, besoins=EXCLUDED.besoins, mna=EXCLUDED.mna, es_tu=EXCLUDED.es_tu, resume_suivi=EXCLUDED.resume_suivi, jours_depuis_suivi=EXCLUDED.jours_depuis_suivi, score_binome=EXCLUDED.score_binome, classification=EXCLUDED.classification, dernier_mood=EXCLUDED.dernier_mood, dernier_cr=EXCLUDED.dernier_cr, mentor_id=EXCLUDED.mentor_id, structure_id=EXCLUDED.structure_id, classe=EXCLUDED.classe, attentes_mentor=EXCLUDED.attentes_mentor, niveau_francais_declare=EXCLUDED.niveau_francais_declare, secteur_vise=EXCLUDED.secteur_vise, synced_at=NOW();`;

  results.push({ json: { query: sql } });
}

return results;
